// Analyze competitive gaps
const gaps = $input.all().map(i => i.json);

if (gaps.length === 0) {
  return [{ json: { has_gaps: false, summary: 'No competitive gaps found' } }];
}

// Group by competitor
const byCompetitor = {};
gaps.forEach(g => {
  if (!byCompetitor[g.competitor_domain]) {
    byCompetitor[g.competitor_domain] = [];
  }
  byCompetitor[g.competitor_domain].push(g);
});

const summary = Object.entries(byCompetitor).map(([domain, keywords]) => ({
  competitor: domain,
  keyword_count: keywords.length,
  top_keywords: keywords.slice(0, 3).map(k => k.keyword)
}));

return [{
  json: {
    has_gaps: true,
    total_gaps: gaps.length,
    by_competitor: summary,
    top_opportunities: gaps.slice(0, 10).map(g => ({
      keyword: g.keyword,
      competitor: g.competitor_domain,
      position: g.competitor_position
    }))
  }
}];

